package cl.duoc.vetcontrol.producto.model;
import jakarta.persistence.*;
import java.math.BigDecimal;
@Entity @Table(name="productos")
public class Producto { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(nullable=false,length=120) private String nombre; @Column(nullable=false,length=50) private String categoria; @Column(nullable=false,precision=10,scale=2) private BigDecimal precio; @Column(nullable=false) private boolean restringido; @Column(nullable=false) private boolean activo=true; public Long getId(){return id;} public void setId(Long id){this.id=id;} public String getNombre(){return nombre;} public void setNombre(String nombre){this.nombre=nombre;} public String getCategoria(){return categoria;} public void setCategoria(String categoria){this.categoria=categoria;} public BigDecimal getPrecio(){return precio;} public void setPrecio(BigDecimal precio){this.precio=precio;} public boolean isRestringido(){return restringido;} public void setRestringido(boolean restringido){this.restringido=restringido;} public boolean isActivo(){return activo;} public void setActivo(boolean activo){this.activo=activo;} }
